截取變數部分字串 start_date=20231202 echo &#34;${start_date:4:2}&#34; # 12 echo &#34;${start_date:0:4}&#34; # 2023 執行 shell script 的時候遇到以下問題 bash: $&#39;\r&#39;: command not found # 解決辦法 sed -i &#39;s/\r$//&#39; build.sh # or dos2unix file.sh 取代的用法 #!/bin/bash CASE_NAME=&#34;$1&#34; REPLACE=&#34;-&#34; JOB_NAME=&#34;ec-token-make-${CASE_NAME//_/$REPLACE}&#34; echo $JOB_NAME 抓取參數 # 当前脚本的文件名 $0 # 传递给脚本或函数的参数。n 是一个数字，表示第几个参数。例如，第一个参数是$1，第二个参数是$2。 $n # 传递给脚本或函数的参数个数。 $# # 传递给脚本或函数的所有参数。 $* # 传递给脚本或函数的所有参数。被双引号(&#34; &#34;)包含时，与 $* 稍有不同，下面将会讲到。 $@ # 上个命令的退出状态，或函数的返回值。 $? # 当前Shell进程ID。对于 Shell 脚本，就是这些脚本所在的进程ID。 $$ example
#!/bin/bash echo &#34;File Name: $0&#34; echo &#34;First Parameter : $1&#34; echo &#34;First Parameter : $2&#34; echo &#34;Quoted Values: $@&#34; echo &#34;Quoted Values: $*&#34; echo &#34;Total Number of Parameters : $#&#34; 直接 assign 一個環境變數,只是可能執行階段結束就不見了 var=value bash 123.sh var=value sh -c &rsquo;echo &ldquo;$var&rdquo;' bash 123.sh value var=&quot;$1&quot; echo &ldquo;$var&rdquo;
